class Solution {
    public int findIntegers(int n) {
        int a = 0, b = 1;
        int res = 1;
        for (int i = 2; i <= n; i++) {
            int c = a + b;
            if ((i & (i >> 1)) != 0) c -= a;
            a = b;
            b = c;
            res += c;
        }
        return res;
    }
}
